mapper.select:
/* SQL ID : MutEvalQstnDAO.listMutEvalQstnEgov 설 명 : 평가 문제 목록 조회 */ SELECT A.QSTN_ID AS qstnCd , A.ASMT_MTL_EVL_RSLT_ID AS evalCd , A.MTL_EVL_TYCD AS evalTypeCd , A.UP_MTL_EVL_QSTN_ID AS parQstnCd , (SELECT B.MTL_EVL_TTL FROM MTL_EVL AS B WHERE B.ASMT_MTL_EVL_RSLT_ID = A.ASMT_MTL_EVL_RSLT_ID) AS evalTitle , A.QSTN_SEQNO AS qstnNo , A.QSTN_CTS AS qstnCts , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm FROM MTL_EVL_QSTN AS A WHERE 1 = 1
AND A.ASMT_MTL_EVL_RSLT_ID = #{evalCd}
AND A.ASMT_MTL_EVL_RSLT_ID = (SELECT ASMT_MTL_EVL_RSLT_ID FROM TB_LMS_MUT_EVAL_RLTN AS B WHERE B.LINK_CD = #{rltnCd} AND EVAL_DIV_CD = #{evalDivCd})
AND A.MTL_EVL_TYCD = #{evalTypeCd}

mapper.delete:
		/*
             SQL ID : MutEvalQstnDAO.delMutEvalQstn
             	설  명 : 평가 문제 삭제
        */
		DELETE FROM MTL_EVL_QSTN
		 WHERE ASMT_MTL_EVL_RSLT_ID = #{evalCd}
		   AND MTL_EVL_TYCD = #{evalTypeCd}

mapper.insert:
		/*
             SQL ID : MutEvalQstnDAO.insertMutEvalQstn
             	설  명 : 평가 문제 등록
        */
        INSERT INTO MTL_EVL_QSTN (
        	  ASMT_MTL_EVL_RSLT_ID
			, QSTN_ID
			, MTL_EVL_TYCD
			, UP_MTL_EVL_QSTN_ID
			, QSTN_SEQNO
			, QSTN_CTS
			, EVL_SCR
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
        ) VALUES (
        	  #{evalCd}
        	, #{qstnCd}
        	, #{evalTypeCd}
        	, #{parQstnCd}
        	, #{qstnNo}
        	, #{qstnCts}
        	, #{evalScore}
        	, #{rgtrId}
        	, FN_DTTM()
        	, #{mdfrId}
        	, FN_DTTM()
        )
